package src.org.apache.nutch.service.resources;

@ Path ( value = "/admin" ) public class AdminResource extends AbstractResource { private final int DELAY_SEC = 1 ; private static final Logger LOG = LoggerFactory . getLogger ( MethodHandles . lookup ( ) . lookupClass ( ) ) ; @ GET @ Path ( value = "/" ) public NutchServerInfo getServerStatus ( ) { NutchServerInfo serverInfo = new NutchServerInfo ( ) ; serverInfo . setConfiguration ( configManager . list ( ) ) ; serverInfo . setStartDate ( new Date ( server . getStarted ( ) ) ) ; serverInfo . setJobs ( jobManager . list ( null , State . ANY ) ) ; serverInfo . setRunningJobs ( jobManager . list ( null , State . RUNNING ) ) ; return serverInfo ; } @ GET @ Path ( value = "/stop" ) public String stopServer ( @ QueryParam ( "force" ) boolean force ) { if ( ! server . canStop ( force ) ) { return "Jobs still running -- Cannot stop server now" ; } scheduleServerStop ( ) ; return "Stopping in server on port " + server . getPort ( ) ; } private void scheduleServerStop ( ) { LOG . info ( "Shutting down server in {} sec" , DELAY_SEC ) ; Thread thread = new Thread ( ) { public void run ( ) { try { Thread . sleep ( DELAY_SEC * 1000 ) ; } catch ( InterruptedException e ) { Thread . currentThread ( ) . interrupt ( ) ; } server . stop ( ) ; LOG . info ( "Service stopped." ) ; } } ; thread . setDaemon ( true ) ; thread . start ( ) ; LOG . info ( "Service shutting down..." ) ; } }